import React, {useRef, useState, useEffect} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import PhotoWrapperSection from '../components/PhotoWrapperSection'
import SellPageInput from '../components/SellPageInput'
import SellPageDropdown from '../components/SellPageDropdown'
import {getDesigner, getSize, getCondition, getCategory, getSubCategory, createListing} from '../WebAPI.js'
import {BlackBackground, PopUpBox} from '../components/utils'

const SellWrapper = styled.form `
display:flex;
flex-direction:column;
align-items:flex-start;
width:55%;
margin:70px auto;
`

const Head = styled.div ``

const Body = styled.div `
margin:40px 0;
`

const PhotoUploadSection = styled.div ``

const Title = styled.div `
font-size:1.8rem;
font-weight:900;
`

const SectionTitle = styled.div `
font-size:1.5rem;
font-weight:800;
letter-spacing:2px;
color:rgba(0,0,0,0.7);
`

const Details = styled.div ``

const GridWrapper =  styled.div `
display:grid;
grid-template-columns: auto auto;
grid-template-rows: auto auto;
grid-gap:60px 60px;
width:100%;
margin:30px 0;
`

const Detail = styled.div `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
font-size:0.9rem;
text-align:center;
line-height:38px;
box-sizing:border-box;
margin-top:30px;
`

const DescriptionInput = styled.textarea `
width:100%;
height:80px;
border:1px solid grey;
color:grey;
border-radius:6px;
margin-top:30px;
box-sizing:border-box;
padding:5px 10px;
font-family:YuGothic;
font-style:italic;
`

const Description = styled.div ``

const Photo = styled.div ``

const FooterWrapper = styled.div `
display:flex;
justify-content:flex-end;
align-items:center;
width:100%;
padding:0 20px;
box-sizing:border-box;
`
const DepartmentAndCategory = styled.div `
width:360px;
border:1px solid grey;
border-radius:4px;
position:absolute;
background-color:white;
box-sizing:border-box;
${props => props.dropdownActive ? null: 'display:none'};
`

const Submit = styled.input `
width:100px;
height:50px;
background-color:rgb(50, 50, 50);
color:white;
border-radius:10px;
border:0;
text-align:center;
line-height:50px;
font-size:0.9rem;
font-weight:800;
&:hover {
	cursor:pointer;
}
`

const Draft = styled.div `
width:150px;
height:50px;
background-color:white;
